---@class LPlayerPrefs
local LPlayerPrefs = LxClass("LPlayerPrefs", nil)
-----------------------------------------------------------------
--- documents/local_ini.json
LPlayerPrefs.INI_LOCAL_PATH = CS.AppPersistentDataPath() .. "playerprefs.json"

--- documents/localization.txt
LPlayerPrefs.LOCALIZATION_PATH = CS.AppPersistentDataPath() .. "Localization/localization.txt"

--- documents/local_sensitive.db
LPlayerPrefs.INI_LOCAL_SENSITIVE_PATH = CS.AppPersistentDataPath() .. "playerprefs_sensitive.db"

--- documents/id(playerid)_ini.json
LPlayerPrefs.INI_PLAYER_PATH = CS.AppPersistentDataPath() .. "%s_prefs.json"

LPlayerPrefs._cacheIniList = nil
LPlayerPrefs._cachePlayerIniList = nil
LPlayerPrefs._cachePlayerIniPath = nil

function LPlayerPrefs.CheckLogOpen()
	if not CS.IsWebGL() then
		local checkPath =  CS.AppPersistentDataPath() .. "env_developer_test"
		local content = LFileHelper.ReadAllTextFromCache(checkPath)
		if content then
			if string.find(content, "log_enable=true") then
				LGameSettings.platformDev = true
				LogWarn("开启游戏日志（来自数据目录设置）...")
			end
		end
	end
end

function LPlayerPrefs.ReadJsonFile(path)
	local strContent = LFileHelper.ReadAllTextFromCache(path)
	local iniContent
	if not string.isempty(strContent) then
		iniContent = JSON.decode(strContent)
	end
	iniContent = iniContent or {}
	return iniContent
end

function LPlayerPrefs.WriteJsonFile(path,dataList)
	if string.isempty(path) then return end
	local content = JSON.encode(dataList)
	if string.isempty(content) then return end
	LFileHelper.WriteAllTextToCache(path,content)
end

function LPlayerPrefs.ReadFileWithEncode(path)
	local strBytes = LFileHelper.ReadAllBytesFromCache(path)
	local strContent
	if strBytes ~= nil then
		strContent = YXUtility.XORDecode(strBytes, "r18");
	end
	local iniContent
	if not string.isempty(strContent) then
		iniContent = JSON.decode(strContent)
	end
	iniContent = iniContent or {}
	return iniContent
end

function LPlayerPrefs.WriteFileWithEncode(path,dataList)
	if string.isempty(path) then return end
	local content = JSON.encode(dataList)
	if string.isempty(content) then return end
	local strBytes = YXUtility.XOREncode(content, "r18");
	LFileHelper.WriteAllBytesToCache(path, strBytes)
end

--- 限制资源修改,true为不可通过GM修改
local _LimitResType = false
function LPlayerPrefs.LimitResType(bLimit)
	_LimitResType = bLimit
end

local _TestLocalizationData = nil
function LPlayerPrefs.GetLocalization()
	if not _TestLocalizationData then
		local oldLocalization
		local strContent = LFileHelper.ReadAllTextFromCache(LPlayerPrefs.LOCALIZATION_PATH)
		if strContent and string.len(strContent) <= 1 then
			oldLocalization = checknumber(strContent)
			strContent = nil
		end
		local content = not string.isempty(strContent)  and JSON.decode(strContent) or nil
		if content == nil then
			content = {
				localization = oldLocalization or 1,
				enableDebug = 0,
				fileFormatVersion = 0,
				resourceId = 1,
				Dimension = 10,
				Font = "OppoSans-Regular",
				platform = "Android",
				exitType = 1,
				speedLimitEnabled = 1,
				poseCfg = "null",
				playLipSync = 1,
			}
			LFileHelper.WriteAllTextToCache(LPlayerPrefs.LOCALIZATION_PATH,JSON.encode(content))
		end
		_TestLocalizationData = checknumber(content["localization"]) or 0
	end
	--LogWarn(string.replace("-----资源类型检测 资源参数 #a1#",_TestLocalizationData))
	return _TestLocalizationData
end

function LPlayerPrefs.SaveLocalization()
	local content = {
		localization = _TestLocalizationData,
		enableDebug = 0,
		fileFormatVersion = 0,
		resourceId = 1,
		Dimension = 10,
		Font = "OppoSans-Regular",
		platform = "Android",
		exitType = 1,
		speedLimitEnabled = 1,
		poseCfg = "null",
		playLipSync = 1,
	}
	LFileHelper.WriteAllTextToCache(LPlayerPrefs.LOCALIZATION_PATH,JSON.encode(content))
end

function LPlayerPrefs.GetIsForceSensitiveRes()
	if _TestLocalizationData then
		return _TestLocalizationData
	end
	return checknumber(LPlayerPrefs.isForceSensitiveRes)
end

function LPlayerPrefs.GMSetLocalization(version)
	if _LimitResType then 
		--LogWarn("-----资源类型检测 不可修改资源参数")
		return 
	end
	--LogWarn(string.replace("-----资源类型检测 资源参数由#a1#修改为#a2#",(_TestLocalizationData or "nil"),version))
	_TestLocalizationData = version
end

local _RecordOrganicData = nil
function LPlayerPrefs.ChangeOrganic()
	_RecordOrganicData = true
	if LPlayerPrefs._cachePlayerIniList then
		LPlayerPrefs.UpdateFirstChangeResType()
	end
end

function LPlayerPrefs.UpdateFirstChangeResType()
	if not _RecordOrganicData then return end
	local firstChangeResType = tonumber(LPlayerPrefs.firstChangeResType) or 0
	if firstChangeResType == 0 then
		LPlayerPrefs.GMSetLocalization(3)
		LPlayerPrefs.SaveLocalization()
		LPlayerPrefs.SetFirstChangeResType(1)
	end
	LPlayerPrefs.CheckOpenSexResType()
end

--- 后台如果开启了裸露屏蔽，则需要把资源改为1
function LPlayerPrefs.CheckOpenSexResType()
	local isOpenSex = gLGameLogin and gLGameLogin:IsOpenSex()
	if isOpenSex then
		local resType = LPlayerPrefs.GetLocalization()
		--LogWarn(string.replace("-----资源类型检测 resType = #a1#",resType))
		if resType == 0 then
			LPlayerPrefs.GMSetLocalization(1)
		end
	end
end

