---本地全局设置
function LPlayerPrefs.InitializePrefs()
	LPlayerPrefs.GetLocalization()

	local dataList = {
		--uuidFirstBoot = "", 		-- 第一次启动保存的设备UUID
		lngFlag = "", 				-- 多语言标记
		lngSysFlag = "",			-- 多语言系统标记
		forceUpdate = "0",			-- 是否强制更新
		musicMute = "false",		-- 音乐开关
		musicVolume = "0.7",		-- 音乐音量
		soundMute = "false",		-- 系统音效开关（UI、战斗等）
		soundVolume = "0.7",		-- 系统音效效音量
		singleSoundMute = "false",	-- 角色音效开关
		singleSoundVolume = "0.7",	-- 角色音效音量
		qualityLv = "0",			-- 画质等级
		highFrameRate = "-1",		-- 高帧率
		--sdkUser = "",				-- sdk 账号
		--sdkDevice = "",				-- sdk 设备标识
		--serverId = "",				-- 上次选中的服务器ID
		--serverName = "",			-- 上次选中的服务器名
		--serverAccount = "",			-- 上次登录的账号
		platformNotice = "",		-- 平台弹出时间
		maskVer = "",				-- 屏蔽字版本
		edtReconnect = "5", 		-- 编辑器模式重连时间
		openClientTextLog = "0",	--富文本id的打印开关
		muteLoginMusic = "false",	--mute login music

		loginFigure = "100001",           --登录形象
		loginRoleRecord = "",       --版本形象更换
		autoUseLoginRole = "1",      --自动使用版本形象
		isFirstLogin = "1", 		 --是否装包，或者卸包重装后的第一次登录
		-- miniGameInStall = "",		 -- 小游戏是否安装过, 格式 id|id|....
		loginFBRed = "0",		 -- 登录界面fb社群红点点击....
		prepareMirrorCall = "",		 --预抽卡数据,格式:可抽卡次数=选择英雄id=已抽卡次数=抽取英雄1|抽取英雄2...=第一次登录时间戳=sdkId
		lockPrepareMirrorCallSdkList = "",--预抽卡已领取英雄sdk列表,格式:sdkId=sdkId=...
		initiativeSetCityMapTheme = "",  --玩家手动设置主城地图皮肤的mapRefId, 格式：serverId1=name1=mapRefId|serverId2=name2=mapRefId...
		otherAudioFlag = "", --设置另外的配音
		wxCollection = 0,						--微信小游戏收藏
		vipChangeOpenVipServiceWnd = 0,						--vip等级变化进行窗口的打开
		isForceSensitiveRes = "1", --强制显示保守版本资源
		isJaAgreeRule = "0", --日本同意规约
		ttFreedSubscriberRP = "0"--TTFeed直流推荐入口红点 每日点击红点
	}
	LPlayerPrefs._cacheIniList = dataList

	local iniPath = LPlayerPrefs.INI_LOCAL_PATH
	local iniContent = LXFW.xpcall(LPlayerPrefs.ReadJsonFile,iniPath)
	if not iniContent then
		LogError("local ini can not decode, content ="..tostring(iniPath))
	end
	iniContent = iniContent or {}
	local iniVal
	local bChange = false
	for k,v in pairs(dataList) do
		iniVal = tostring(iniContent[k] or "")
		if (iniVal == "") then
			if not bChange and iniVal ~= v then
				bChange = true
			end
			iniVal = v
		end
		dataList[k] = iniVal
		rawset(LPlayerPrefs, k, iniVal)
	end

	local lngMap = {}
	lngMap[0] = "zhcn"
	lngMap[1] = "zhtw"
	lngMap[2] = "enus"

	if (string.isempty(LPlayerPrefs.lngFlag)) then
		dataList["lngFlag"] = LGameSettings.platformDefaultLng or ""
		rawset(LPlayerPrefs, "lngFlag", dataList["lngFlag"])
		LogWarn("LPlayerPrefs.lngFlag = " ..LPlayerPrefs.lngFlag)
		bChange = true
	else
		--local needLngFlag = lngMap[LGameSettings.platformRegion]
		--if needLngFlag and needLngFlag ~= LPlayerPrefs.lngFlag then
		--	dataList["lngFlag"] = LGameSettings.platformDefaultLng or ""
		--	rawset(LPlayerPrefs, "lngFlag", dataList["lngFlag"])
		--	LogWarn("LPlayerPrefs.lngFlag = " ..LPlayerPrefs.lngFlag)
		--	bChange = true
		--end
		local recordLngFlag = PJXCenter.GameMgr:GetGameEnvVar("lngFlag")
		if not string.isempty(recordLngFlag) then
			PJXCenter.GameMgr:SetGameEnvVar("lngFlag", "")
			if LPlayerPrefs.lngFlag ~= recordLngFlag then
				rawset(LPlayerPrefs, "lngFlag", recordLngFlag)
				dataList["lngFlag"] = recordLngFlag
				LogWarn("LPlayerPrefs.lngFlag = " ..LPlayerPrefs.lngFlag)
				bChange = true
			end
		end

	end

	if LGameSettings.isNoSound then
		LPlayerPrefs.musicVolume = "0"
		LPlayerPrefs.soundVolume = "0"
		LPlayerPrefs.singleSoundVolume = "0"
	end

	if bChange then
		LXFW.xpcall(LPlayerPrefs.WriteJsonFile, iniPath, dataList)
	end

	--敏感信息不明文放置
	local sensitiveDataList = {
		uuidFirstBoot = "", 		-- 第一次启动保存的设备UUID
		sdkUser = "",				-- sdk 账号
		sdkDevice = "",				-- sdk 设备标识
		serverId = "",				-- 上次选中的服务器ID
		serverName = "",			-- 上次选中的服务器名
		serverAccount = "",			-- 上次登录的账号
		devAccountMode = "",		-- 上次开发登陆模式
		sdkguid = "",				-- 上次登录guid
		sdksex = "",				-- 上次登录性别
	}
	LPlayerPrefs._cacheSensitiveDataList = sensitiveDataList

	local sensitiveContent = LXFW.xpcall(LPlayerPrefs.ReadFileWithEncode, LPlayerPrefs.INI_LOCAL_SENSITIVE_PATH)
	sensitiveContent = sensitiveContent or {}

	bChange = false
	for k,v in pairs(sensitiveDataList) do
		iniVal = tostring(sensitiveContent[k] or "")
		if (iniVal == "") then
			if not bChange and iniVal ~= v then
				bChange = true
			end
			iniVal = v
		end
		sensitiveDataList[k] = iniVal
		rawset(LPlayerPrefs, k, iniVal)
	end

	if (string.isempty(LPlayerPrefs.uuidFirstBoot)) then
		local uuid = LNativeHelper.GetUUID()
		if (string.isempty(uuid)) then
			uuid = USystemInfo.deviceUniqueIdentifier
		end
		sensitiveDataList["uuidFirstBoot"] = uuid
		rawset(LPlayerPrefs, "uuidFirstBoot", uuid or "")
		bChange = true
		LPlayerPrefs.IS_NEW_UUID_SET = true
	end

	if bChange then
		LXFW.xpcall(LPlayerPrefs.WriteFileWithEncode, LPlayerPrefs.INI_LOCAL_SENSITIVE_PATH, sensitiveDataList)
	end

	LPlayerPrefs.CheckLogOpen()

	return true
end

