	LPlayerPrefs._cachePlayerIniList = dataList
	playerId = "id" ..tostring(playerId)
	local iniPath = CS.AppPersistentDataPath()..playerId.."_ini.json"
	LPlayerPrefs._cachePlayerIniPath = iniPath

	local iniContent = LXFW.xpcall(LPlayerPrefs.ReadJsonFile,iniPath)
	iniContent = iniContent or {}
	local iniVal
	local bChange = false
	for k,v in pairs(dataList) do
		iniVal = tostring(iniContent[k] or "")
		if (iniVal == "") then
			if not bChange and iniVal ~= v then
				bChange = true
			end
			iniVal = v
		end
		dataList[k] = iniVal
		rawset(LPlayerPrefs, k, iniVal)
	end

	if bChange then
		LXFW.xpcall(LPlayerPrefs.WriteJsonFile, iniPath, dataList)
	end
	LPlayerPrefs.UpdateFirstChangeResType()
end


------------------------------------------------------------------
function LPlayerPrefs.SaveSensitiveIni(keyStr, value)
	return LPlayerPrefs.SaveSensitiveString(LPlayerPrefs._cacheSensitiveDataList,LPlayerPrefs.INI_LOCAL_SENSITIVE_PATH,keyStr,value)
end

function LPlayerPrefs.SaveSensitiveString(dataList,path,keyStr, value)
	local oldVal = rawget(LPlayerPrefs, keyStr)
	if (value == nil) then return oldVal end
	value = tostring(value)
	if (value == oldVal) then return oldVal end
	rawset(LPlayerPrefs, keyStr, value)
	if dataList then
		dataList[keyStr] = value
		LXFW.xpcall(LPlayerPrefs.WriteFileWithEncode, path, dataList)
	end
	return value
end

------------------------------------------------------------------
function LPlayerPrefs.SaveLocalIni(keyStr, value)
	return LPlayerPrefs.SaveIniString(LPlayerPrefs._cacheIniList,LPlayerPrefs.INI_LOCAL_PATH,keyStr,value)
end

function LPlayerPrefs.SavePlayerIni(keyStr, value)
	return LPlayerPrefs.SaveIniString(LPlayerPrefs._cachePlayerIniList,LPlayerPrefs._cachePlayerIniPath,keyStr,value)
end

function LPlayerPrefs.SaveIniString(dataList,path,keyStr, value)
	local oldVal = rawget(LPlayerPrefs, keyStr)
	if (value == nil) then return oldVal end
	value = tostring(value)
	if (value == oldVal) then return oldVal end
	rawset(LPlayerPrefs, keyStr, value)
	if dataList then
		dataList[keyStr] = value
		LXFW.xpcall(LPlayerPrefs.WriteJsonFile, path, dataList)
	end
	return value
end

